class Solution:
    def rearrangeCharacters(self, s, target):
        from collections import Counter
        sc = Counter(s)
        tc = Counter(target)
        copies = 0
        while True:
            for ch, need in tc.items():
                if sc[ch] < need:
                    return copies
            for ch, need in tc.items():
                sc[ch] -= need
            copies += 1

