var rearrangeCharacters = function(s, target) {
    const sc = {}, tc = {};
    for (const ch of s) sc[ch] = (sc[ch] || 0) + 1;
    for (const ch of target) tc[ch] = (tc[ch] || 0) + 1;
    let ans = Infinity;
    for (const ch in tc) {
        ans = Math.min(ans, Math.floor((sc[ch] || 0) / tc[ch]));
    }
    return ans;
};
